#include <bits/stdc++.h>
using namespace std;
const int N=1e4+4,mod=1e9+7;
int f[N][102],d;
char s[N];
void init(){
	f[0][0]=1;
	for(int i=1;i<N;i++)
		for(int j=0;j<d;j++)
			for(int k=0;k<=9;k++)
				f[i][j]=(f[i][j]+f[i-1][(d+j-k%d)%d])%mod;
}
int ans(){
	int n=strlen(s+1),a[N];
	for(int i=1;i<=n;i++)
		a[i]=s[n-i+1]-'0';
	int res=0,last=0;
	for(int i=n;i;i--){
		for(int j=0;j<a[i];j++)
			res=(res+f[i-1][(2*d-last-j%d)%d])%mod;
		last=(last+a[i])%d;
		if(i==1 && !last)
			res++;
	}
	return res-1;
}
int main(){
	scanf("%d",&d);
	scanf("%s",s+1);
	init();
	printf("%d",ans());
	return 0;
}
